import React from 'react';
import './Waveform.css';

function Waveform() {
  const bars = Array.from({ length: 40 }, () => Math.random() * 100);
  return (
    <div className="waveform">
      {bars.map((height, i) => (
        <div key={i} className="waveform-bar" style={{ height: `${Math.max(height, 10)}%` }} />
      ))}
    </div>
  );
}

export default Waveform;
